import React from 'react';
import { Card, CardContent, Box, Typography, Stack } from '@mui/material';
import { PieChart } from '@mui/x-charts';
import response from './response.json';

interface InvoiceData {
  invoices: {
    totalPending: {
      count: number;
      amount: number;
    };
    totalPaid: {
      count: number;
      amount: number;
    };
    totalOverdue: {
      count: number;
      amount: number;
    };
  };
}

export default function Widget() {
  const invoiceData = response.data as InvoiceData;
  const { totalPending, totalPaid, totalOverdue } = invoiceData.invoices;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 320, maxWidth: 380, bgcolor: '#000000' }} elevation={2}>
      <CardContent sx={{ p: 2 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" sx={{ color: '#FFFFFF' }}>
              Invoice Summary
            </Typography>
            <Typography variant="body2" sx={{ color: '#94A3B8' }}>
              Finance Suite v1.0
            </Typography>
          </Box>

          <Box sx={{ width: '100%', height: 200 }}>
            <PieChart
              series={[
                {
                  data: [
                    { id: 'Paid', value: totalPaid.amount, label: 'Paid' },
                    { id: 'Pending', value: totalPending.amount, label: 'Pending' },
                    { id: 'Overdue', value: totalOverdue.amount, label: 'Overdue' },
                  ],
                  colors: ['#4A5568', '#E53E3E', '#E0E7FF'],
                },
              ]}
              sx={{
                '& .MuiPieChart-label': {
                  fill: '#FFFFFF',
                  fontSize: 12,
                },
              }}
            />
          </Box>

          <Stack direction="row" spacing={1.5} sx={{ justifyContent: 'space-between' }}>
            <Box>
              <Typography variant="caption" sx={{ color: '#94A3B8' }}>
                Pending
              </Typography>
              <Typography variant="body2" sx={{ color: '#FFFFFF' }}>
                {totalPending.count} (${totalPending.amount.toLocaleString()})
              </Typography>
            </Box>
            <Box>
              <Typography variant="caption" sx={{ color: '#94A3B8' }}>
                Paid
              </Typography>
              <Typography variant="body2" sx={{ color: '#FFFFFF' }}>
                {totalPaid.count} (${totalPaid.amount.toLocaleString()})
              </Typography>
            </Box>
            <Box>
              <Typography variant="caption" sx={{ color: '#94A3B8' }}>
                Overdue
              </Typography>
              <Typography variant="body2" sx={{ color: '#FFFFFF' }}>
                {totalOverdue.count} (${totalOverdue.amount.toLocaleString()})
              </Typography>
            </Box>
          </Stack>
        </Stack>
      </CardContent>
    </Card>
  );
}
